import { useMemo, useState } from 'react';
import './App.css';

const books = [
  {
    id: 1,
    name: 'Uvod u programiranje',
    author: 'Milan Tair',
    image:
      'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=900&q=80',
    description:
      'Knjiga je namenjena studentima koji prvi put uce osnove programiranja i algoritamskog razmisljanja.',
    category: 'Strucna literatura',
    city: 'Novi Sad',
    availableFrom: '2026-06-01',
    owner: 'Ana D.',
    rating: 5,
    numReviews: 12,
    status: 'Dostupna',
  },
  {
    id: 2,
    name: 'Uvod u mikroprocesorske sisteme',
    author: 'Petar Knezevic',
    image:
      'https://images.unsplash.com/photo-1515879218367-8466d910aaa4?auto=format&fit=crop&w=900&q=80',
    description:
      'Ocuvana skripta za pripremu kolokvijuma i ispita iz mikroprocesorskih sistema.',
    category: 'Skripta',
    city: 'Beograd',
    availableFrom: '2026-06-10',
    owner: 'Marko S.',
    rating: 4.5,
    numReviews: 8,
    status: 'Dostupna',
  },
  {
    id: 3,
    name: 'Na Drini cuprija',
    author: 'Ivo Andric',
    image:
      'https://images.unsplash.com/photo-1544947950-fa07a98d237f?auto=format&fit=crop&w=900&q=80',
    description:
      'Klasik domace knjizevnosti, pogodan za skolsko citanje i ljubitelje istorijskih romana.',
    category: 'Domaca knjizevnost',
    city: 'Nis',
    availableFrom: '2026-05-25',
    owner: 'Milica R.',
    rating: 4.8,
    numReviews: 16,
    status: 'Na razmeni',
  },
  {
    id: 4,
    name: 'Zlocin i kazna',
    author: 'Fjodor Dostojevski',
    image:
      'https://images.unsplash.com/photo-1495446815901-a7297e633e8d?auto=format&fit=crop&w=900&q=80',
    description:
      'Dobro ocuvano izdanje sa nekoliko podvucenih pasusa. Dostupno za pozajmicu na dogovoreni period.',
    category: 'Klasici',
    city: 'Subotica',
    availableFrom: '2026-07-05',
    owner: 'Jovana P.',
    rating: 4.9,
    numReviews: 21,
    status: 'Dostupna',
  },
  {
    id: 5,
    name: 'Clean Code',
    author: 'Robert C. Martin',
    image:
      'https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&w=900&q=80',
    description:
      'Prakticna literatura za programere. Korisna za projekat, praksu i pripremu tehnickog intervjua.',
    category: 'Programiranje',
    city: 'Novi Sad',
    availableFrom: '2026-06-03',
    owner: 'Lena V.',
    rating: 4.7,
    numReviews: 10,
    status: 'Dostupna',
  },
  {
    id: 6,
    name: 'Mali princ',
    author: 'Antoan de Sent Egziperi',
    image:
      'https://images.unsplash.com/photo-1526243741027-444d633d7365?auto=format&fit=crop&w=900&q=80',
    description:
      'Kratka i lepa knjiga za vikend citanje. Vlasnik je spreman za brzu razmenu u gradu.',
    category: 'Beletristika',
    city: 'Kragujevac',
    availableFrom: '2026-06-15',
    owner: 'Sara K.',
    rating: 4.6,
    numReviews: 14,
    status: 'Dostupna',
  },
];

const requests = [
  { id: 1, user: 'Stefan L.', type: 'Dodavanje knjige', book: '1984', status: 'Na cekanju' },
  { id: 2, user: 'Ana D.', type: 'Izmena dostupnosti', book: 'Zlocin i kazna', status: 'Na cekanju' },
  { id: 3, user: 'Milica R.', type: 'Brisanje knjige', book: 'Staro izdanje gramatike', status: 'Odobreno' },
];

function Rating({ value, text }) {
  return (
    <div className="rating" aria-label={`Ocena ${value}`}>
      {[1, 2, 3, 4, 5].map((star) => (
        <span key={star}>{value >= star ? '★' : value >= star - 0.5 ? '☆' : '☆'}</span>
      ))}
      {text && <span className="rating-text">{text}</span>}
    </div>
  );
}

function Header({ cartCount, user, screen, setScreen, onLogout }) {
  return (
    <header className="site-header">
      <div className="container nav-shell">
        <button className="brand" type="button" onClick={() => setScreen('home')}>
          <span className="brand-mark">RK</span>
          <span>
            <strong>Razmena knjiga</strong>
            <small>Fakultet tehnickih nauka u Novom Sadu</small>
          </span>
        </button>

        <nav className="main-nav" aria-label="Navigacija">
          <button className={screen === 'home' ? 'active' : ''} type="button" onClick={() => setScreen('home')}>
            Pocetna
          </button>
          <button className={screen === 'cart' ? 'active' : ''} type="button" onClick={() => setScreen('cart')}>
            Korpa <span className="badge">{cartCount}</span>
          </button>
          {user ? (
            <button className={screen === 'profile' ? 'active' : ''} type="button" onClick={() => setScreen('profile')}>
              {user.name}
            </button>
          ) : (
            <button className={screen === 'login' ? 'active' : ''} type="button" onClick={() => setScreen('login')}>
              Prijava
            </button>
          )}
          {user?.isAdmin && (
            <button className={screen === 'admin' ? 'active' : ''} type="button" onClick={() => setScreen('admin')}>
              Admin
            </button>
          )}
          {user && (
            <button type="button" onClick={onLogout}>
              Odjava
            </button>
          )}
        </nav>
      </div>
    </header>
  );
}

function ProductCard({ book, onOpen }) {
  return (
    <article className="product-card">
      <button className="image-link" type="button" onClick={() => onOpen(book.id)}>
        <img src={book.image} alt={book.name} />
      </button>
      <div className="product-body">
        <button className="title-link" type="button" onClick={() => onOpen(book.id)}>
          <strong>{book.name}</strong>
        </button>
        <p>{book.author}</p>
        <Rating value={book.rating} text={`${book.numReviews} recenzija`} />
        <h3>{book.city}</h3>
      </div>
    </article>
  );
}

function HomeScreen({ onOpen }) {
  const [category, setCategory] = useState('Sve');
  const [query, setQuery] = useState('');

  const categories = ['Sve', ...new Set(books.map((book) => book.category))];
  const filteredBooks = useMemo(
    () =>
      books.filter((book) => {
        const byCategory = category === 'Sve' || book.category === category;
        const byQuery = `${book.name} ${book.author} ${book.city}`.toLowerCase().includes(query.toLowerCase());
        return byCategory && byQuery;
      }),
    [category, query],
  );

  return (
    <>
      <section className="hero">
        <div>
          <p>Online zajednica za pozajmicu</p>
          <h1>Razmeni knjigu bez kupovine i prati gde se trenutno nalazi.</h1>
        </div>
      </section>

      <div className="toolbar">
        <h2>Nove knjige</h2>
        <div className="filters-row">
          <input
            type="search"
            placeholder="Pretraga knjiga"
            value={query}
            onChange={(event) => setQuery(event.target.value)}
          />
          <select value={category} onChange={(event) => setCategory(event.target.value)}>
            {categories.map((item) => (
              <option key={item}>{item}</option>
            ))}
          </select>
        </div>
      </div>

      <section className="product-grid">
        {filteredBooks.map((book) => (
          <ProductCard book={book} key={book.id} onOpen={onOpen} />
        ))}
      </section>
    </>
  );
}

function ProductScreen({ book, onBack, onAddToCart }) {
  return (
    <section className="product-screen">
      <button className="back-button" type="button" onClick={onBack}>
        Nazad
      </button>
      <div className="product-detail">
        <img src={book.image} alt={book.name} />
        <div>
          <h1>{book.name}</h1>
          <Rating value={book.rating} text={`${book.numReviews} recenzija`} />
          <p>{book.description}</p>
          <dl>
            <div>
              <dt>Autor</dt>
              <dd>{book.author}</dd>
            </div>
            <div>
              <dt>Kategorija</dt>
              <dd>{book.category}</dd>
            </div>
            <div>
              <dt>Vlasnik</dt>
              <dd>{book.owner}</dd>
            </div>
            <div>
              <dt>Dostupno od</dt>
              <dd>{book.availableFrom}</dd>
            </div>
          </dl>
        </div>
        <aside className="exchange-card">
          <div>
            <span>Status</span>
            <strong>{book.status}</strong>
          </div>
          <div>
            <span>Grad</span>
            <strong>{book.city}</strong>
          </div>
          <button disabled={book.status !== 'Dostupna'} type="button" onClick={() => onAddToCart(book)}>
            Dodaj u korpu za razmenu
          </button>
        </aside>
      </div>
    </section>
  );
}

function CheckoutSteps({ active }) {
  const steps = ['Prijava', 'Podaci o razmeni', 'Pregled zahteva'];

  return (
    <ol className="checkout-steps">
      {steps.map((step, index) => (
        <li className={index <= active ? 'enabled' : ''} key={step}>
          {step}
        </li>
      ))}
    </ol>
  );
}

function CartScreen({ cartItems, onRemove, onCheckout }) {
  const totalDays = cartItems.reduce((sum, item) => sum + item.days, 0);

  return (
    <section className="cart-layout">
      <div>
        <h1>Korpa za razmenu</h1>
        {cartItems.length === 0 ? (
          <p className="message">Korpa je prazna. Vrati se na pocetnu i izaberi knjigu.</p>
        ) : (
          <div className="cart-list">
            {cartItems.map((item) => (
              <article key={item.id}>
                <img src={item.image} alt={item.name} />
                <div>
                  <strong>{item.name}</strong>
                  <span>{item.author}</span>
                </div>
                <span>{item.days} dana</span>
                <button type="button" onClick={() => onRemove(item.id)}>
                  Obrisi
                </button>
              </article>
            ))}
          </div>
        )}
      </div>
      <aside className="summary-card">
        <h2>Ukupno: {cartItems.length} knjiga</h2>
        <p>Predvidjeno trajanje razmene: {totalDays} dana</p>
        <button disabled={cartItems.length === 0} type="button" onClick={onCheckout}>
          Nastavi razmenu
        </button>
      </aside>
    </section>
  );
}

function LoginScreen({ onLogin, onRegister }) {
  const [email, setEmail] = useState('ana@student.ftn.rs');
  const [password, setPassword] = useState('123456');

  return (
    <section className="form-container">
      <h1>Prijava</h1>
      <form
        onSubmit={(event) => {
          event.preventDefault();
          onLogin(email);
        }}
      >
        <label>
          Email adresa
          <input value={email} onChange={(event) => setEmail(event.target.value)} />
        </label>
        <label>
          Lozinka
          <input type="password" value={password} onChange={(event) => setPassword(event.target.value)} />
        </label>
        <button type="submit">Prijavi se</button>
      </form>
      <p>
        Nemate nalog?{' '}
        <button className="inline-button" type="button" onClick={onRegister}>
          Registrujte se
        </button>
      </p>
    </section>
  );
}

function RegisterScreen({ onLogin }) {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');

  return (
    <section className="form-container">
      <h1>Registrujte se</h1>
      <form
        onSubmit={(event) => {
          event.preventDefault();
          onLogin(email || 'korisnik@student.ftn.rs', name || 'Novi korisnik');
        }}
      >
        <label>
          Ime
          <input value={name} onChange={(event) => setName(event.target.value)} placeholder="Upisite ime" />
        </label>
        <label>
          Email adresa
          <input value={email} onChange={(event) => setEmail(event.target.value)} placeholder="Upisite email" />
        </label>
        <label>
          Lozinka
          <input type="password" placeholder="Upisite lozinku" />
        </label>
        <button type="submit">Registruj se</button>
      </form>
    </section>
  );
}

function ShippingScreen({ onSubmit }) {
  return (
    <section className="form-container">
      <CheckoutSteps active={1} />
      <h1>Podaci o razmeni</h1>
      <form
        onSubmit={(event) => {
          event.preventDefault();
          onSubmit();
        }}
      >
        <label>
          Adresa preuzimanja
          <input required placeholder="Unesite adresu" />
        </label>
        <label>
          Grad
          <input required placeholder="Unesite grad" />
        </label>
        <label>
          Period razmene
          <select defaultValue="21 dana">
            <option>14 dana</option>
            <option>21 dana</option>
            <option>30 dana</option>
          </select>
        </label>
        <button type="submit">Nastavi</button>
      </form>
    </section>
  );
}

function ProfileScreen({ user, cartItems }) {
  return (
    <section className="profile-grid">
      <div className="panel">
        <h1>Moj profil</h1>
        <p>{user.name}</p>
        <p>{user.email}</p>
      </div>
      <div className="panel">
        <h2>Moje razmene</h2>
        {cartItems.length === 0 ? (
          <p>Nema aktivnih zahteva.</p>
        ) : (
          cartItems.map((item) => <p key={item.id}>{item.name} - zahtev u pripremi</p>)
        )}
      </div>
    </section>
  );
}

function AdminScreen() {
  return (
    <section className="panel">
      <h1>Administracija zahteva</h1>
      <div className="admin-list">
        {requests.map((request) => (
          <article key={request.id}>
            <div>
              <strong>{request.type}</strong>
              <span>
                {request.book} - {request.user}
              </span>
            </div>
            <span className={`status ${request.status === 'Odobreno' ? 'approved' : 'waiting'}`}>
              {request.status}
            </span>
            <div>
              <button type="button">Odobri</button>
              <button type="button">Odbij</button>
            </div>
          </article>
        ))}
      </div>
    </section>
  );
}

function Footer() {
  return (
    <footer className="footer">
      <div className="container">
        <p>&copy; {new Date().getFullYear()} Razmena knjiga. Sva prava zadrzana.</p>
      </div>
    </footer>
  );
}

function App() {
  const [screen, setScreen] = useState('home');
  const [selectedBookId, setSelectedBookId] = useState(books[0].id);
  const [cartItems, setCartItems] = useState([]);
  const [user, setUser] = useState(null);

  const selectedBook = books.find((book) => book.id === selectedBookId) || books[0];

  function openBook(id) {
    setSelectedBookId(id);
    setScreen('product');
  }

  function addToCart(book) {
    setCartItems((current) => {
      if (current.some((item) => item.id === book.id)) {
        return current;
      }

      return [...current, { ...book, days: 21 }];
    });
    setScreen('cart');
  }

  function login(email, name = 'Ana Dzanic') {
    setUser({ name, email, isAdmin: email.toLowerCase().includes('admin') });
    setScreen('home');
  }

  function logout() {
    setUser(null);
    setScreen('home');
  }

  function checkout() {
    if (!user) {
      setScreen('login');
      return;
    }

    setScreen('shipping');
  }

  return (
    <>
      <Header
        cartCount={cartItems.length}
        onLogout={logout}
        screen={screen}
        setScreen={setScreen}
        user={user}
      />
      <main className="container main-content">
        {screen === 'home' && <HomeScreen onOpen={openBook} />}
        {screen === 'product' && (
          <ProductScreen book={selectedBook} onAddToCart={addToCart} onBack={() => setScreen('home')} />
        )}
        {screen === 'cart' && (
          <CartScreen
            cartItems={cartItems}
            onCheckout={checkout}
            onRemove={(id) => setCartItems((current) => current.filter((item) => item.id !== id))}
          />
        )}
        {screen === 'login' && <LoginScreen onLogin={login} onRegister={() => setScreen('register')} />}
        {screen === 'register' && <RegisterScreen onLogin={login} />}
        {screen === 'shipping' && <ShippingScreen onSubmit={() => setScreen('profile')} />}
        {screen === 'profile' && user && <ProfileScreen cartItems={cartItems} user={user} />}
        {screen === 'admin' && <AdminScreen />}
      </main>
      <Footer />
    </>
  );
}

export default App;
